import re
import html


class ExtractXMLValueComponent(Component):
    """Extract value from XML/HTML tags in text"""

    display_name = "Extract XML Value"
    description = "Extract value between XML tags from Data object"
    icon = "code-xml"

    inputs = [
        MessageTextInput(
            name="input_data",
            display_name="Input Data",
            info="Data object containing XML text",
            required=True
        ),
        MessageTextInput(
            name="start_tag",
            display_name="Start Tag",
            info="Starting XML tag (e.g., '<Value>')",
            value="<Value>",
            required=True
        ),
        MessageTextInput(
            name="end_tag",
            display_name="End Tag",
            info="Ending XML tag (e.g., '</Value>')",
            value="</Value>",
            required=True
        ),
        MessageTextInput(
            name="text_field",
            display_name="Text Field",
            info="Field name containing XML text",
            value="text",
            required=True
        )
    ]

    outputs = [
        Output(
            display_name="Message Output", 
            name="message_output", 
            method="extract_value"
        )
    ]

    def extract_text_from_data(self, data: Union[Data, List[Data], dict]) -> str:
        """Extract text from various input formats"""

        # Handle list input
        if isinstance(data, list):
            if not data:
                return ""
            data = data[0]

        # Handle Data object
        if isinstance(data, Data):
            if hasattr(data, 'data'):
                data_dict = data.data
            elif hasattr(data, 'model_dump'):
                data_dict = data.model_dump()
            else:
                data_dict = {}
        elif isinstance(data, dict):
            data_dict = data
        else:
            return str(data)

        return data_dict.get(self.text_field, "")

    def decode_text(self, text: str) -> str:
        """Decode escaped sequences in text"""
        if '\\x' in text:
            try:
                # Handle escaped unicode sequences
                text = text.encode('latin-1').decode('unicode-escape')
            except:
                pass

        # Handle HTML entities
        if '&#' in text or '&amp;' in text or '&lt;' in text or '&gt;' in text:
            text = html.unescape(text)

        return text

    def extract_value_between_tags(self, text: str, start_tag: str, end_tag: str) -> Optional[str]:
        """Extract value between start and end tags"""
        if not text:
            return None

        # Method 1: Regex search
        start_escaped = re.escape(start_tag)
        end_escaped = re.escape(end_tag)
        pattern = f"{start_escaped}(.*?){end_escaped}"

        matches = re.findall(pattern, text, re.DOTALL)
        if matches:
            return matches[0].strip()

        # Method 2: String search (fallback)
        start_pos = text.find(start_tag)
        if start_pos != -1:
            end_pos = text.find(end_tag, start_pos + len(start_tag))
            if end_pos != -1:
                return text[start_pos + len(start_tag):end_pos].strip()

        return None

    def extract_value(self) -> Message:
        """Main extraction method"""

        # Get input values
        input_data = self.input_data
        start_tag = self.start_tag
        end_tag = self.end_tag
        text_field = self.text_field

        # Store for use in helper methods
        self.text_field = text_field

        # Extract text from input data
        text = self.extract_text_from_data(input_data)

        if not text:
            return Message(
                text=f"No text found in field '{text_field}'",
                data={"error": "No text found"}
            )

        # Decode text
        decoded_text = self.decode_text(text)

        # Extract value between tags
        extracted_value = self.extract_value_between_tags(decoded_text, start_tag, end_tag)

        if extracted_value:
            # Create success message
            return Message(
                text=extracted_value,
                data={
                    "extracted_value": extracted_value,
                    "start_tag": start_tag,
                    "end_tag": end_tag,
                    "text_field": text_field,
                    "original_text_preview": text[:500] if len(text) > 500 else text
                }
            )
        else:
            # Try to find any numeric value as fallback
            numeric_pattern = r'(\d+[,.]\d+)'
            numeric_matches = re.findall(numeric_pattern, decoded_text)

            if numeric_matches:
                extracted_value = numeric_matches[0]
                return Message(
                    text=extracted_value,
                    data={
                        "extracted_value": extracted_value,
                        "warning": "Tags not found, using numeric pattern",
                        "all_numeric_values": numeric_matches
                    }
                )

            # Return error message
            error_msg = f"Value not found between {start_tag} and {end_tag}"
            return Message(
                text=error_msg,
                data={
                    "error": error_msg,
                    "searched_text": decoded_text[:1000]
                }
            )

from typing import Any

from loguru import logger

from langflow.base.tools.run_flow import RunFlowBaseComponent
from langflow.helpers.flow import run_flow
from langflow.schema.dotdict import dotdict


class RunFlowComponent(RunFlowBaseComponent):
    display_name = "Run Flow"
    description = (
        "Creates a tool component from a Flow that takes all its inputs and runs it. "
        " \n **Select a Flow to use the tool mode**"
    )
    documentation: str = "https://docs.langflow.org/components-logic#run-flow"
    beta = True
    name = "RunFlow"
    icon = "Workflow"

    inputs = RunFlowBaseComponent._base_inputs
    outputs = RunFlowBaseComponent._base_outputs

    async def update_build_config(self, build_config: dotdict, field_value: Any, field_name: str | None = None):
        if field_name == "flow_name_selected":
            build_config["flow_name_selected"]["options"] = await self.get_flow_names()
            missing_keys = [key for key in self.default_keys if key not in build_config]
            if missing_keys:
                msg = f"Missing required keys in build_config: {missing_keys}"
                raise ValueError(msg)
            if field_value is not None:
                try:
                    graph = await self.get_graph(field_value)
                    build_config = self.update_build_config_from_graph(build_config, graph)
                except Exception as e:
                    msg = f"Error building graph for flow {field_value}"
                    logger.exception(msg)
                    raise RuntimeError(msg) from e
        return build_config

    async def run_flow_with_tweaks(self):
        tweaks: dict = {}

        flow_name_selected = self._attributes.get("flow_name_selected")
        parsed_flow_tweak_data = self._attributes.get("flow_tweak_data", {})
        if not isinstance(parsed_flow_tweak_data, dict):
            parsed_flow_tweak_data = parsed_flow_tweak_data.dict()

        if parsed_flow_tweak_data != {}:
            for field in parsed_flow_tweak_data:
                if "~" in field:
                    [node, name] = field.split("~")
                    if node not in tweaks:
                        tweaks[node] = {}
                    tweaks[node][name] = parsed_flow_tweak_data[field]
        else:
            for field in self._attributes:
                if field not in self.default_keys and "~" in field:
                    [node, name] = field.split("~")
                    if node not in tweaks:
                        tweaks[node] = {}
                    tweaks[node][name] = self._attributes[field]

        return await run_flow(
            inputs=None,
            output_type="all",
            flow_id=None,
            flow_name=flow_name_selected,
            tweaks=tweaks,
            user_id=str(self.user_id),
            session_id=self.graph.session_id or self.session_id,
        )

